// ── Frost Breaker (targeting: multi-energize tapped targets) ───────────
SPELL_REGISTRY.set('Frost Breaker', {
  effectType: 'multi-energize',
  logEmoji: '❄️⚡',
  gerrymanderable: false,
  castable: ({ room }) => countEligibleTappedTargets(room) > 0,
  setup: ({ room, playerId, heldCard }) => {
    const x = heldCard?.paidCost || 0;
    const crystalPenalty = countOpponentCrystals(room, playerId);
    const tapped = countEligibleTappedTargets(room);
    if (x > tapped - 1) return null; // overpaid (shouldn't happen — client caps it)
    const targetsNeeded = Math.max(0, x + 1 - crystalPenalty);
    const actualTargets = Math.min(targetsNeeded, tapped);
    if (actualTargets <= 0) return null;
    return { targetsNeeded: actualTargets, damage: 5, excludeCasterStudent: playerId };
  },
  fizzleError: 'No valid tapped targets for Frost Breaker',
});

// ── Lightball: castable + resolve ──────────────────────────────────────
SPELL_REGISTRY.get('Lightball').castable = ({ player }) => {
  if (!player) return true;
  return hasOwnPoisonedTarget(player);
};

SPELL_REGISTRY.get('Lightball').resolve = ({ room, playerId, player }) => {
  const healTargets = [];
  if (player.chosenStudent && !player.studentDead && (player.chosenStudent.poisonStacks || 0) > 0) {
    const old = player.chosenStudent.poisonStacks;
    player.chosenStudent.poisonStacks = 0;
    console.log(`💡 Lightball: ${player.name}'s student cleansed of ${old} poison stack(s)`);
    healTargets.push({ playerId, type: 'student', familiarIndex: -1, rawAmount: 10 });
  }
  for (let i = 0; i < (player.familiars || []).length; i++) {
    const fam = player.familiars[i];
    if (!fam || fam.currentHp <= 0) continue;
    if ((fam.poisonStacks || 0) > 0) {
      const old = fam.poisonStacks;
      fam.poisonStacks = 0;
      console.log(`💡 Lightball: ${player.name}'s ${fam.name} cleansed of ${old} poison stack(s)`);
      healTargets.push({ playerId, type: 'familiar', familiarIndex: i, rawAmount: 10 });
    }
  }
  console.log(`💡 ${player.name}'s Lightball cleansed ${healTargets.length} target(s) — healing 10 each`);
  return { healTargets, auraColor: 'lightball' };
};

// ── Neurotoxin: resolve ────────────────────────────────────────────────
SPELL_REGISTRY.get('Neurotoxin').resolve = ({ room, playerId, player }) => {
  // Phase 1: Tap all untapped targets with 1+ poison stacks
  const tappedTargets = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && !p.studentDead && !p.tappedStudent && !hasAntiMagicBlade(p) && (p.chosenStudent.poisonStacks || 0) > 0) {
      // Invisibility Cloak: block opponent's Neurotoxin tap on student
      if (pid !== playerId && tryConsumeInvisibleStack(room, p)) {
        console.log(`👻 Invisibility Cloak: ${p.name}'s student is Invisible — Neurotoxin tap blocked!`);
      } else {
        forcedTapStudent(room, p);
        tappedTargets.push({ playerId: pid, type: 'student', familiarIndex: -1 });
      }
    }
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const fam = p.familiars[i];
      if (!fam || fam.currentHp <= 0) continue;
      if ((p.tappedFamiliars || []).includes(i)) continue;
      if (room._jungleMoatActive) continue; // Jungle Moat: skip familiar tap
      if ((fam.poisonStacks || 0) > 0) {
        forcedTapFamiliar(room, p, i);
        tappedTargets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
      }
    }
  }
  // Phase 2: Add 1 poison stack to ALL living targets
  const poisonTargets = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && !p.studentDead && !hasAntiMagicBlade(p)) {
      if (pid !== playerId && tryConsumeInvisibleStack(room, p)) {
        console.log(`👻 Invisibility Cloak: ${p.name}'s student is Invisible — Neurotoxin poison blocked!`);
      } else {
        p.chosenStudent.poisonStacks = (p.chosenStudent.poisonStacks || 0) + 1;
        propagateVoodooPoison(room, pid, 1);
        poisonTargets.push({ playerId: pid, type: 'student', familiarIndex: -1 });
      }
    }
    const classPet = hasClassPetImmunity(p);
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const fam = p.familiars[i];
      if (!fam || fam.currentHp <= 0) continue;
      if (classPet || isMechImmune(fam)) continue;
      if (isGoldenHind(fam)) continue;
      if (room._jungleMoatActive) continue; // Jungle Moat: skip familiar poison
      fam.poisonStacks = (fam.poisonStacks || 0) + 1;
      poisonTargets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
    }
  }
  console.log(`☠️☣️ ${player.name}'s Neurotoxin: tapped ${tappedTargets.length}, poisoned ${poisonTargets.length} target(s)`);
  for (const t of poisonTargets) addPoisonCloudEvent(room, t.playerId, t.type, t.familiarIndex);
  room.neurotoxinEvent = { tappedTargets, poisonTargets };
  return {};
};

// ── Armageddon: resolve ────────────────────────────────────────────────
SPELL_REGISTRY.get('Armageddon').resolve = ({ room, playerId, player, _skipSnareCheck }) => {
  const damage = 5 * (room.examRound || 1);
  const targets = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && !p.studentDead) targets.push({ playerId: pid, type: 'student' });
    for (let i = 0; i < (p.familiars || []).length; i++) {
      if (p.familiars[i] && p.familiars[i].currentHp > 0) {
        targets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
      }
    }
  }
  if (!_skipSnareCheck && targets.length === 1) {
    return { amsSingleTarget: { ...targets[0], spellName: 'Armageddon' } };
  }
  if (!_skipSnareCheck && targets.length > 1) {
    return { amsMultiTarget: { targets, spellName: 'Armageddon' } };
  }
  console.log(`🔥🔥🔥 ARMAGEDDON! Round ${room.examRound} — ${damage} damage to ALL targets!`);
  room.armageddonEvent = { casterId: playerId, damage, round: room.examRound || 1 };
  return { armageddonPending: true, armageddonTargets: targets, armageddonDamage: damage };
};

