// ── Arms Trade: castable + helpers ─────────────────────────────────────
// Requires ≥2 students (main students only) that collectively have equips
// with at least 2 different names.
SPELL_REGISTRY.get('Arms Trade').castable = ({ room }) => {
  const equipNames = new Set();
  const studentsWithEquips = [];
  for (const [, p] of room.players) {
    if (p.left || p.won || p.studentDead || !p.chosenStudent) continue;
    if ((p.equips || []).length === 0) continue;
    studentsWithEquips.push({ playerId: p.id, equips: p.equips });
    for (const e of p.equips) equipNames.add(e.name);
  }
  // Need at least 2 different students with equips AND at least 2 distinct equip names
  return studentsWithEquips.length >= 2 && equipNames.size >= 2;
};

// ── Aurora Borealis: castable + setup ──────────────────────────────────
// Scans all opponents' discards for eligible spells (not Aurora Borealis,
// subject to isSpellCastable checks from the caster's perspective).
function getAuroraBorealisEligibleSpells(room, playerId) {
  const eligible = [];
  for (const [pid, p] of room.players) {
    if (pid === playerId || p.left) continue;
    (p.discardPile || []).forEach((card, i) => {
      if (card.type !== 'Spell') return;
      if (card.name === 'Aurora Borealis') return;
      if (!isSpellCastable(room, card, room.players.get(playerId), playerId)) return;
      eligible.push({ discardIndex: i, ownerId: pid, ownerName: p.name, card });
    });
  }
  return eligible;
}

SPELL_REGISTRY.get('Aurora Borealis').castable = ({ room, player }) => {
  const pid = player ? [...room.players.entries()].find(([, p]) => p === player)?.[0] : null;
  if (!pid) return false;
  return getAuroraBorealisEligibleSpells(room, pid).length > 0;
};

SPELL_REGISTRY.get('Aurora Borealis').setup = ({ room, playerId }) => {
  const eligible = getAuroraBorealisEligibleSpells(room, playerId);
  if (eligible.length === 0) return null;
  return { eligibleSpells: eligible, canCancel: true };
};

// ── Big Oopsie: adjacency helper + resolve ─────────────────────────────
// Returns the caster + up to 2 players seated immediately adjacent (circular).
function getBigOopsieAffectedPlayers(room, casterId) {
  const active = getActivePlayers(room).sort((a, b) => a.seat - b.seat);
  if (active.length === 0) return [];
  const casterIdx = active.findIndex(p => p.id === casterId);
  if (casterIdx === -1) return [];
  const affected = new Set([casterId]);
  const n = active.length;
  if (n >= 2) affected.add(active[(casterIdx - 1 + n) % n].id);
  if (n >= 3) affected.add(active[(casterIdx + 1) % n].id);
  return [...affected];
}

SPELL_REGISTRY.get('Big Oopsie').resolve = ({ room, playerId, _skipSnareCheck }) => {
  const affectedIds = getBigOopsieAffectedPlayers(room, playerId);
  const targets = [];
  for (const pid of affectedIds) {
    const p = room.players.get(pid);
    if (!p || p.left) continue;
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const fam = p.familiars[i];
      if (fam && fam.currentHp > 0) {
        targets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
      }
    }
  }
  if (!_skipSnareCheck && targets.length === 1) {
    return { amsSingleTarget: { ...targets[0], spellName: 'Big Oopsie' } };
  }
  if (!_skipSnareCheck && targets.length > 1) {
    return { amsMultiTarget: { targets, spellName: 'Big Oopsie' } };
  }
  console.log(`💥 Big Oopsie! ${room.players.get(playerId)?.name} — ${targets.length} familiar(s) will take 10`);
  room.bigOopsieEvent = { casterId: playerId, affectedIds };
  return { bigOopsiePending: true, bigOopsieTargets: targets };
};

SPELL_REGISTRY.get('Big Oopsie').castable = ({ room, player }) => {
  const pid = player ? [...room.players.entries()].find(([, p]) => p === player)?.[0] : null;
  if (!pid) return false;
  const affectedIds = getBigOopsieAffectedPlayers(room, pid);
  return affectedIds.some(aid => {
    const p = room.players.get(aid);
    return p && !p.left && (p.familiars || []).some(f => f && f.currentHp > 0);
  });
};

// ── Body Swap: castable + setup ────────────────────────────────────────
// Requires at least one Student in any player's discard pile.
function getBodySwapDiscardStudents(room) {
  const students = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    (p.discardPile || []).forEach((card, i) => {
      if (card.type === 'Student') {
        students.push({ ownerId: pid, ownerName: p.name, discardIndex: i, card });
      }
    });
  }
  return students;
}

SPELL_REGISTRY.get('Body Swap').castable = ({ room }) => {
  for (const [, p] of room.players) {
    if (p.left) continue;
    if ((p.discardPile || []).some(c => c.type === 'Student')) return true;
  }
  return false;
};

SPELL_REGISTRY.get('Body Swap').setup = ({ room }) => {
  const discardStudents = getBodySwapDiscardStudents(room);
  if (discardStudents.length === 0) return null;
  return { discardStudents, canCancel: true };
};

// ── Butterfly Cloud: castable + setup ──────────────────────────────────
// Requires at least one opponent with living targets.
SPELL_REGISTRY.get('Butterfly Cloud').castable = ({ room, player }) => {
  const pid = player ? [...room.players.entries()].find(([, p]) => p === player)?.[0] : null;
  if (!pid) return false;
  for (const [id, p] of room.players) {
    if (id === pid || p.left) continue;
    if ((p.chosenStudent && !p.studentDead) || (p.familiars || []).some(f => f && f.currentHp > 0)) return true;
  }
  return false;
};

SPELL_REGISTRY.get('Butterfly Cloud').setup = ({ room, playerId }) => {
  const validOpponents = [];
  for (const [id, p] of room.players) {
    if (id === playerId || p.left) continue;
    if ((p.chosenStudent && !p.studentDead) || (p.familiars || []).some(f => f && f.currentHp > 0)) {
      validOpponents.push(id);
    }
  }
  if (validOpponents.length === 0) return null;
  return { validOpponents, canCancel: true };
};

// ── Butterfly Form: castable + setup ───────────────────────────────────
// Requires at least one alive Student on the board (any player).
function hasButterflyForm(player) {
  return (player.equips || []).some(e => !e.malfunctioning && e.name === 'Butterfly Form');
}

SPELL_REGISTRY.get('Butterfly Form').castable = ({ room }) => {
  for (const [, p] of room.players) {
    if (p.left || p.studentDead || !p.chosenStudent || hasAntiMagicBlade(p)) continue;
    return true;
  }
  return false;
};

SPELL_REGISTRY.get('Butterfly Form').setup = ({ room }) => {
  const validTargets = [];
  for (const [id, p] of room.players) {
    if (p.left || p.studentDead || !p.chosenStudent || hasAntiMagicBlade(p)) continue;
    validTargets.push({ playerId: id, playerName: p.name });
  }
  if (validTargets.length === 0) return null;
  return { validTargets, canCancel: true };
};

// ── Cataclysm: resolve ─────────────────────────────────────────────────
// ── Explosion: ordered target array helper ────────────────────────────────
/**
 * Build the global ordered target array for Explosion adjacency.
 * Order per player (in examTurnOrder): fam[0], fam[2], fam[4]..., student, fam[1], fam[3], fam[5]...
 * Only living, non-summoned entities. Array wraps (circular).
 */
function buildExplosionArray(room) {
  const order = room.examTurnOrder || [];
  const arr = [];
  for (const pid of order) {
    const p = room.players.get(pid);
    if (!p || p.left) continue;
    const fams = p.familiars || [];
    // Even indices: descending (highest index = furthest from student, index 0 = closest)
    const evenIdxs = [];
    for (let i = 0; i < fams.length; i += 2) {
      const f = fams[i];
      if (f && f.currentHp > 0 && !f.summoned) evenIdxs.push(i);
    }
    for (let j = evenIdxs.length - 1; j >= 0; j--) {
      arr.push({ playerId: pid, type: 'familiar', familiarIndex: evenIdxs[j] });
    }
    if (p.chosenStudent && !p.studentDead && !hasAntiMagicBlade(p)) arr.push({ playerId: pid, type: 'student' });
    // Odd indices: ascending (index 1 = closest to student on right)
    for (let i = 1; i < fams.length; i += 2) {
      const f = fams[i];
      if (f && f.currentHp > 0 && !f.summoned) arr.push({ playerId: pid, type: 'familiar', familiarIndex: i });
    }
  }
  return arr;
}

// ── Explosion: castable + setup ───────────────────────────────────────────
{
  SPELL_REGISTRY.get('Explosion').castable = ({ room }) => {
    const arr = buildExplosionArray(room);
    // At least one targetable entry (not Hind-immune)
    for (const t of arr) {
      const owner = room.players.get(t.playerId);
      if (!owner) continue;
      if (t.type === 'familiar') {
        const fam = owner.familiars?.[t.familiarIndex];
        if (fam && !isGoldenHind(fam)) return true;
      } else {
        return true; // students always targetable as primary
      }
    }
    return false;
  };

  SPELL_REGISTRY.get('Explosion').setup = ({ room, playerId }) => {
    const arr = buildExplosionArray(room);
    // Eligible primary targets: anything except Golden Hind
    const eligibleTargets = arr.filter(t => {
      const owner = room.players.get(t.playerId);
      if (!owner) return false;
      if (t.type === 'familiar') {
        const fam = owner.familiars?.[t.familiarIndex];
        return fam && !isGoldenHind(fam);
      }
      return true;
    });
    if (eligibleTargets.length === 0) return null;
    return { eligibleTargets, targetsNeeded: 1, canCancel: true };
  };
}

// ── Great Filter: castable + resolve ─────────────────────────────────────
{
  const isGFTarget = (p, fam) =>
    fam && fam.currentHp > 0 && fam.currentHp <= 5 &&
    !hasClassPetImmunity(p) && !isMechImmune(fam);

  SPELL_REGISTRY.get('Great Filter').castable = ({ room }) => {
    for (const [, p] of room.players) {
      if (p.left) continue;
      if ((p.familiars || []).some(f => isGFTarget(p, f))) return true;
    }
    return false;
  };

  SPELL_REGISTRY.get('Great Filter').resolve = ({ room, playerId, _skipSnareCheck }) => {
    // Collect all eligible targets now (pre-kill, for animation)
    const targets = [];
    for (const [pid, p] of room.players) {
      if (p.left) continue;
      (p.familiars || []).forEach((f, fi) => {
        if (isGFTarget(p, f)) targets.push({ playerId: pid, type: 'familiar', familiarIndex: fi });
      });
    }
    if (!_skipSnareCheck && targets.length === 1) {
      return { amsSingleTarget: { ...targets[0], spellName: 'Great Filter' } };
    }
    if (!_skipSnareCheck && targets.length > 1) {
      return { amsMultiTarget: { targets, spellName: 'Great Filter' } };
    }
    if (!room.spellAnimEvents) room.spellAnimEvents = [];
    room.spellAnimEvents.push({ type: 'great-filter', targets });
    console.log(`💜 Great Filter: ${targets.length} familiar(s) marked for destruction`);
    // Defer actual kills — gate on animation
    return { greatFilterPending: true, greatFilterTargets: targets };
  };
}

// ── Reincarnation: castable + setup ──────────────────────────────────────
SPELL_REGISTRY.get('Reincarnation').castable = ({ room, playerId }) => {
  for (const [pid, p] of room.players) {
    if (pid === playerId || p.left || p.won) continue;
    if (p.studentDead && p.chosenStudent) return true;
  }
  return false;
};
SPELL_REGISTRY.get('Reincarnation').setup = ({ room, playerId }) => {
  const eligibleTargets = [];
  for (const [pid, p] of room.players) {
    if (pid === playerId || p.left || p.won) continue;
    if (p.studentDead && p.chosenStudent)
      eligibleTargets.push({ playerId: pid, type: 'student', familiarIndex: -1 });
  }
  if (eligibleTargets.length === 0) return null;
  return { eligibleTargets, targetsNeeded: 1, canCancel: true };
};

/**
 * When a player wins, check if any Reincarnation casters have a bond with them
 * and grant those casters a co-win (if their own student is alive and they haven't won).
 * Returns array of new winner IDs added.
 */
function checkReincarnationBonds(room, newWinnerIds) {
  // The Stink Pile: clear stinky debuffs applied by any new winner
  if (!room._resolvingStinkPile) {
    room._resolvingStinkPile = true;
    resolveStinkPileOnWin(room, newWinnerIds);
    delete room._resolvingStinkPile;
  }

  if (!room.reincarnationBonds || room.reincarnationBonds.length === 0) return [];
  const coWinners = [];
  for (const newId of newWinnerIds) {
    for (const bond of room.reincarnationBonds) {
      if (bond.revivedPlayerId !== newId) continue;
      const caster = room.players.get(bond.casterPlayerId);
      if (!caster || caster.left || caster.won || caster.studentDead) continue;
      caster.won = true;
      room.winners.push(bond.casterPlayerId);
      caster.chosenStudent = null;
      caster.tappedStudent = true;
      room.winAnnouncements = (room.winAnnouncements || []).concat([{ playerId: bond.casterPlayerId, playerName: caster.name }]);
      coWinners.push(bond.casterPlayerId);
      console.log(`✨ Reincarnation bond: ${caster.name} co-wins because their revived player ${room.players.get(newId)?.name || newId} won!`);
    }
  }
  return coWinners;
}

/**
 * The Stink Pile: when a player who applied Stinky debuffs wins,
 * clear all Stinky debuffs they applied. If winner slots remain,
 * the freed players also win immediately.
 */
function resolveStinkPileOnWin(room, newWinnerIds) {
  for (const winnerId of newWinnerIds) {
    // Find all players stinkied by this winner
    const stinkyPlayerIds = [];
    for (const [pid, p] of room.players) {
      if (p.stinky && p.stinkyAppliedBy === winnerId) {
        stinkyPlayerIds.push(pid);
      }
    }
    if (stinkyPlayerIds.length === 0) continue;

    // Clear all stinky debuffs applied by this winner
    for (const pid of stinkyPlayerIds) {
      const p = room.players.get(pid);
      if (!p) continue;
      delete p.stinky;
      delete p.stinkyAppliedBy;
      console.log(`💩✨ The Stink Pile: ${p.name}'s Stinky debuff cleared (applied by ${room.players.get(winnerId)?.name || winnerId} who won)`);
    }

    // Check if winner slots remain — if so, freed players who met escape get in
    const needed = Math.floor(room.startingPlayerCount / 2);
    const freedWinners = [];
    // Use previewRegularEscapeWinners to find who now qualifies
    const escapeReady = previewRegularEscapeWinners(room);
    for (const esc of escapeReady) {
      if (room.winners.length >= needed && needed > 0) break; // no more slots
      if (!stinkyPlayerIds.includes(esc.playerId)) continue; // only freed players
      const p = room.players.get(esc.playerId);
      if (!p || p.left || p.won || p.studentDead || !p.chosenStudent) continue;
      p.won = true;
      room.winners.push(esc.playerId);
      p.chosenStudent = null;
      p.tappedStudent = true;
      p.discardPile.push(...(p.equips || []));
      p.equips = [];
      freedWinners.push({ playerId: esc.playerId, playerName: p.name });
      console.log(`💩🎉 ${p.name} WINS — Stinky debuff cleared and escape condition still met!`);
    }
    if (freedWinners.length > 0) {
      room.winAnnouncements = (room.winAnnouncements || []).concat(freedWinners);
      checkReincarnationBonds(room, freedWinners.map(w => w.playerId));
    }
  }
}

// ── Rockfall: castable + setup ────────────────────────────────────────────
