// ── Live Show: resolve + vote handlers ───────────────────────────────────
SPELL_REGISTRY.get('Live Show').resolve = ({ room, playerId, player }) => {
  // Voters = all non-left players except caster (disconnected included — they vote on reconnect)
  const voters = [];
  for (const [pid, p] of room.players) {
    if (pid === playerId || p.left) continue;
    voters.push(pid);
  }
  if (voters.length === 0) {
    // No voters — instant no-win (shouldn't normally reach here)
    return {};
  }
  room.pendingLiveShow = {
    casterId: playerId,
    casterName: player.name,
    voters: new Set(voters), // players who still need to vote
    yesVotes: 0,
    noVotes: 0,
    totalVoters: voters.length,
    // Don't store responses — just counts
  };
  console.log(`🎤 ${player.name} casts Live Show — ${voters.length} voter(s) prompted`);
  return { liveShowPending: true };
};

// ── Iceage: castable + resolve ────────────────────────────────────────────
{
  const iceageTappable = (p, playerId) => {
    if (p.id === playerId || p.left || p.disconnected) return false;
    const tapBlocked = hasChillyDogProtection(p) || hasIfritProtection(p);
    if (tapBlocked) return false;
    const classPet = hasClassPetImmunity(p);
    const angelwing = hasAngelwingBackpack(p);
    // Check student
    if (!tapBlocked && !hasSunSword(p) && p.chosenStudent && !p.studentDead && !p.tappedStudent) return true;
    // Check familiars
    if (!angelwing && !classPet) {
      for (let i = 0; i < (p.familiars || []).length; i++) {
        const f = p.familiars[i];
        if (f && f.currentHp > 0 && !(p.tappedFamiliars || []).includes(i) && !isMechImmune(f)) return true;
      }
    }
    return false;
  };

  SPELL_REGISTRY.get('Iceage').castable = ({ room, player, playerId }) => {
    const cid = playerId || (player ? [...room.players.entries()].find(([,p]) => p === player)?.[0] : null);
    for (const [pid, p] of room.players) {
      if (iceageTappable({ ...p, id: pid }, cid)) return true;
    }
    return false;
  };

  SPELL_REGISTRY.get('Iceage').resolve = ({ room, playerId, _skipSnareCheck }) => {
    // First pass: count tappable targets across all opponents
    const tappableTargets = [];
    for (const [pid, p] of room.players) {
      if (pid === playerId || p.left || p.disconnected) continue;
      const tapBlocked = hasChillyDogProtection(p) || hasIfritProtection(p);
      if (tapBlocked) continue;
      const classPet = hasClassPetImmunity(p);
      const angelwing = hasAngelwingBackpack(p);
      if (!hasSunSword(p) && !hasAntiMagicBlade(p) && p.chosenStudent && !p.studentDead && !p.tappedStudent) {
        tappableTargets.push({ playerId: pid, type: 'student', familiarIndex: -1 });
      }
      if (!angelwing && !classPet) {
        for (let i = 0; i < (p.familiars || []).length; i++) {
          const f = p.familiars[i];
          if (!f || f.currentHp <= 0) continue;
          if ((p.tappedFamiliars || []).includes(i)) continue;
          if (isMechImmune(f)) continue;
          tappableTargets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
        }
      }
    }

    if (!_skipSnareCheck && tappableTargets.length === 1) {
      return { amsSingleTarget: { ...tappableTargets[0], spellName: 'Iceage' } };
    }
    if (!_skipSnareCheck && tappableTargets.length > 1) {
      return { amsMultiTarget: { targets: tappableTargets, spellName: 'Iceage' } };
    }

    // Normal resolve: tap everything (skip zone-protected player)
    const tapped = [];
    for (const [pid, p] of room.players) {
      if (pid === playerId || p.left || p.disconnected) continue;
      if (room._antiMagicZoneProtectedId === pid) {
        console.log(`🛡️ Anti Magic Zone: ${p.name}'s targets protected from Iceage`);
        continue;
      }
      const tapBlocked = hasChillyDogProtection(p) || hasIfritProtection(p);
      if (tapBlocked) { console.log(`🧊 Iceage: ${p.name} protected (Chilly Dog/Ifrit)`); continue; }
      const classPet = hasClassPetImmunity(p);
      const angelwing = hasAngelwingBackpack(p);
      // Student
      if (!hasSunSword(p) && !hasAntiMagicBlade(p) && p.chosenStudent && !p.studentDead && !p.tappedStudent) {
        if (tryConsumeInvisibleStack(room, p)) {
          console.log(`👻 Iceage: ${p.name}'s student blocked by Invisibility Cloak`);
        } else {
          forcedTapStudent(room, p);
          tapped.push({ playerId: pid, type: 'student', familiarIndex: -1 });
        }
      }
      // Familiars
      if (!angelwing && !classPet && !room._jungleMoatActive) {
        for (let i = 0; i < (p.familiars || []).length; i++) {
          const f = p.familiars[i];
          if (!f || f.currentHp <= 0) continue;
          if ((p.tappedFamiliars || []).includes(i)) continue;
          if (isMechImmune(f)) continue;
          forcedTapFamiliar(room, p, i);
          tapped.push({ playerId: pid, type: 'familiar', familiarIndex: i });
        }
      }
    }
    console.log(`🧊 Iceage: tapped ${tapped.length} target(s)`);
    if (!room.spellAnimEvents) room.spellAnimEvents = [];
    room.spellAnimEvents.push({ type: 'iceage' });
    return {};
  };
}

