// ── Fireshield: instant resolve — equip to own student immediately ────────
SPELL_REGISTRY.get('Fireshield').resolve = ({ room, playerId, player, card }) => {
  // Remove from discard — the instant-spell path already pushed the card there,
  // but equip-subtype spells should only live on the board, not in both places
  const discIdx = player.discardPile.indexOf(card);
  if (discIdx !== -1) player.discardPile.splice(discIdx, 1);
  if (!player.equips) player.equips = [];
  player.equips.push(card);
  // Hot Potato: flag for advanceExamTurn check (instant resolve can't defer inline)
  if (room.phase === 'exam') room._hotPotatoPending = { targetPlayerId: playerId, cardRef: card, cardName: card.name, cardPath: card.path || null };
  if (!room.equipEvents) room.equipEvents = [];
  room.equipEvents.push({ playerId });
  console.log(`🔥🛡️ ${player.name} equips Fireshield on ${player.chosenStudent?.name ?? 'their student'}`);
  return {};
};

