// ── Dream Dust: resolve + auto-stamp new summons ──────────────────────────
SPELL_REGISTRY.get('Dream Dust').resolve = ({ room, playerId, player, _skipSnareCheck }) => {
  // Build target list: caster's own living familiars
  const targets = [];
  for (let i = 0; i < (player.familiars || []).length; i++) {
    const fam = player.familiars[i];
    if (fam && fam.currentHp > 0 && !fam.dreamDust) {
      targets.push({ playerId, type: 'familiar', familiarIndex: i });
    }
  }
  if (!_skipSnareCheck && targets.length === 1) {
    return { amsSingleTarget: { ...targets[0], spellName: 'Dream Dust' } };
  }
  if (!_skipSnareCheck && targets.length > 1) {
    return { amsMultiTarget: { targets, spellName: 'Dream Dust' } };
  }

  // Anti Magic Zone: skip if caster is zone-protected
  if (room._antiMagicZoneProtectedId === playerId) {
    console.log(`🛡️ Anti Magic Zone: ${player.name}'s familiars protected from Dream Dust`);
    return {};
  }

  player.dreamDustActive = true;
  let count = 0;
  for (const fam of (player.familiars || [])) {
    if (!fam) continue;
    if (fam && fam.currentHp > 0 && !fam.dreamDust) {
      fam.dreamDust = true;
      fam._dreamDustOwner = playerId;
      count++;
    }
  }
  console.log(`🫧 ${player.name} casts Dream Dust — ${count} Familiar(s) buffed`);
  if (!room.spellAnimEvents) room.spellAnimEvents = [];
  room.spellAnimEvents.push({ type: 'dream-dust-cast', playerId });
  return {};
};

// ── Dread: inject castable + resolve using server-side deleteFamiliar ─────
{
  // Helper: effective cost for Dread (variable-cost familiars use paidCost)
  const dreadEffectiveCost = (fam) => {
    if (fam.cost === -1) return fam.paidCost != null ? fam.paidCost : 0;
    return fam.cost ?? 0;
  };
  // Helper: is this familiar eligible for Dread (alive, not summoned-student, not immune)
  const dreadEligible = (fam, owner) => {
    if (!fam || fam.currentHp <= 0) return false;
    if (fam.summoned) return false;                  // summoned students skip
    if (hasClassPetImmunity(owner)) return false;    // Class Pet protects all of owner's familiars
    if (isMechImmune(fam)) return false;             // Mech immunity
    return true;
  };

  SPELL_REGISTRY.get('Dread').castable = ({ room }) => {
    for (const [, p] of room.players) {
      if (p.left) continue;
      if ((p.familiars || []).some(f => dreadEligible(f, p))) return true;
    }
    return false;
  };

  SPELL_REGISTRY.get('Dread').resolve = ({ room, player, playerId, _skipSnareCheck }) => {
    // Find minimum effective cost among all eligible familiars
    let minCost = Infinity;
    for (const [, p] of room.players) {
      if (p.left) continue;
      for (const fam of (p.familiars || [])) {
        if (!fam) continue;
        if (!dreadEligible(fam, p)) continue;
        const c = dreadEffectiveCost(fam);
        if (c < minCost) minCost = c;
      }
    }
    if (minCost === Infinity) {
      console.log(`👁️ ${player.name} casts Dread — no eligible Familiars found (fizzle)`);
      return {};
    }

    // Collect all targets at minimum cost
    const toDelete = [];
    for (const [pid, p] of room.players) {
      if (p.left) continue;
      for (let fi = (p.familiars || []).length - 1; fi >= 0; fi--) {
        const fam = p.familiars[fi];
        if (!dreadEligible(fam, p)) continue;
        if (dreadEffectiveCost(fam) === minCost) toDelete.push({ pid, fi });
      }
    }

    if (!_skipSnareCheck && toDelete.length === 1) {
      return { amsSingleTarget: { playerId: toDelete[0].pid, type: 'familiar', familiarIndex: toDelete[0].fi, spellName: 'Dread' } };
    }
    if (!_skipSnareCheck && toDelete.length > 1) {
      const _dreadTargets = toDelete.map(d => ({ playerId: d.pid, type: 'familiar', familiarIndex: d.fi }));
      return { amsMultiTarget: { targets: _dreadTargets, spellName: 'Dread' } };
    }

    // Delete all simultaneously — skip zone-protected player's targets
    const deletedNames = [];
    for (const { pid, fi } of toDelete) {
      if (room._antiMagicZoneProtectedId === pid) {
        console.log(`🛡️ Anti Magic Zone: ${room.players.get(pid)?.name}'s familiar protected from Dread`);
        continue;
      }
      const p = room.players.get(pid);
      if (!p) continue;
      const fam = p.familiars[fi];
      if (!fam || fam.currentHp <= 0) continue;
      const del = deleteFamiliar(room, pid, fi, playerId);
      if (del) {
        deletedNames.push(`${del.name} (${p.name})`);
        resolveBomblebeeExplosions(room, playerId);
      }
    }
    console.log(`👁️ ${player.name} casts Dread — cost ${minCost}: deleted [${deletedNames.join(', ')}]`);

    if (!room.spellAnimEvents) room.spellAnimEvents = [];
    room.spellAnimEvents.push({ type: 'dread-cast' });

    return { dreadPendingContinuation: true };
  };
}

