/**
 * Try to consume one Invisible stack from a player's student.
 * Returns true if a stack was consumed (effect is blocked), false if no stacks.
 * Also records a visual block event.
 */
function tryConsumeInvisibleStack(room, player) {
  if ((player.invisibleStacks || 0) <= 0) return false;
  player.invisibleStacks--;
  console.log(`👻 Invisibility Cloak: ${player.name}'s student is Invisible — effect blocked! (${player.invisibleStacks} stacks remaining)`);
  if (!room.invisibleBlockEvents) room.invisibleBlockEvents = [];
  room.invisibleBlockEvents.push({ playerId: player.id });
  return true;
}

/**
 * Clear all Invisible stacks at end of round.
 */
function clearAllInvisibleStacks(room) {
  for (const [, p] of room.players) {
    if ((p.invisibleStacks || 0) > 0) {
      console.log(`👻 ${p.name}'s Invisible stacks cleared at end of round`);
      p.invisibleStacks = 0;
    }
  }
}

