/**
 * Check if a familiar is protected by Diamond Golem's passive aura.
 * Returns true if the owner controls at least 1 alive Diamond Golem
 * AND the target familiar's base cost is ≤ 1.
 */
function hasDiamondGolemProtection(owner, familiar) {
  if (!familiar || !owner) return false;
  const baseCost = familiar.cost ?? 99;
  if (baseCost > 1) return false;
  return (owner.familiars || []).some(f =>
    f && f.currentHp > 0 && (f.name === 'Diamond Golem' || (f.isClone && f.cloneSourceName === 'Diamond Golem'))
  );
}

/**
 * Get a student's effective ATK (base currentAtk + equip bonuses like Anti-Magic Blade).
 */
/**
 * Count the ATK bonus from alive Warhorses (including Clones) on a player's board.
 * Each alive Warhorse grants +5 ATK to the main student.
 */
function getWarhorseAtkBonus(player) {
  let count = 0;
  for (const f of (player.familiars || [])) {
    if (!f || f.currentHp <= 0 || f.passiveNegated) continue;
    if (f.name === 'Warhorse' || (f.isClone && f.originalName === 'Warhorse')) count++;
  }
  return count * 5;
}

