/**
 * Frozen Scythe: after an eligible student attack, prompt the attacker to
 * select 1 untapped familiar from any player's board to tap.
 * Chilly Dog / Ifrit protection is respected (their owner's familiars cannot be targeted).
 */
function setupFrozenScythePrompt(room, playerId, afterFn) {
  const player = room.players.get(playerId);
  if (!player || player.left || player.studentDead || !hasFrozenScythe(player)) {
    afterFn();
    return;
  }

  // Build list of eligible untapped familiars across all players
  const eligibleTargets = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    // Chilly Dog / Ifrit protect opponents' familiars from being tapped (not the attacker's own)
    if (pid !== playerId && (hasChillyDogProtection(p) || hasIfritProtection(p))) continue;
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const fam = p.familiars[i];
      if (!fam || fam.currentHp <= 0) continue;
      if (p.tappedFamiliars.includes(i)) continue;
      eligibleTargets.push({ playerId: pid, familiarIndex: i, name: fam.name });
    }
  }

  if (eligibleTargets.length === 0) { afterFn(); return; }

  const maxSelect = Math.min(countFrozenScythes(player), eligibleTargets.length);
  console.log(`❄️ Frozen Scythe: prompting ${player.name} to tap up to ${maxSelect} familiar(s)`);
  room.pendingFrozenScythe = { playerId, eligibleTargets, maxSelect, afterFn };
  broadcastRoomState(room);
}

