function setupBombArrowPrompt(room, playerId, excludedTargets, afterFn) {
  const buildEligible = (excludeKeys) => {
    const list = [];
    for (const [pid, p] of room.players) {
      if (p.left) continue;
      if (p.chosenStudent && !p.studentDead) {
        const key = `${pid}:student`;
        if (!excludeKeys.has(key)) list.push({ playerId: pid, type: 'student' });
      }
      for (let i = 0; i < (p.familiars || []).length; i++) {
        const f = p.familiars[i];
        if (!f || f.currentHp <= 0) continue;
        const key = `${pid}:familiar:${i}`;
        if (!excludeKeys.has(key)) list.push({ playerId: pid, type: 'familiar', familiarIndex: i });
      }
    }
    return list;
  };

  const excludeKeys = new Set(
    excludedTargets.map(t =>
      t.type === 'student' ? `${t.playerId}:student` : `${t.playerId}:familiar:${t.familiarIndex}`
    )
  );

  let eligible = buildEligible(excludeKeys);

  // Edgelord edge-case: attack hit every living target, so exclusion is meaningless —
  // lift it and allow any target.
  if (eligible.length === 0) {
    eligible = buildEligible(new Set());
  }

  if (eligible.length === 0) {
    // Truly nothing alive to shoot at — fizzle
    console.log(`🏹💣 Bomb Arrow: no eligible targets — fizzles`);
    afterFn();
    return;
  }

  const timer = setTimeout(() => {
    if (room.pendingBombArrow?.playerId !== playerId) return;
    console.log(`🏹💣 Bomb Arrow timeout for ${playerId} — auto-targeting first eligible`);
    const autoTarget = room.pendingBombArrow.eligible[0];
    room.pendingBombArrow = null;
    applyBombArrowShot(room, playerId, autoTarget, afterFn);
  }, BOMB_ARROW_TIMEOUT_MS);

  room.pendingBombArrow = { playerId, eligible, afterFn, timer };
  console.log(`🏹💣 Bomb Arrow: prompting ${room.players.get(playerId)?.name} to pick a target (${eligible.length} eligible)`);
}

/**
 * Apply the 5-damage Bomb Arrow shot to the chosen target.
 */
// ══════════════════════════════════════════════════════════════════════════
// DOOMSDAY BOMB — equip counter + detonation prompt
// ══════════════════════════════════════════════════════════════════════════

/**
 * After a basic attack or Edgelord Cleave, prompt each Doomsday Bomb with
 * counters to potentially detonate. Bombs are processed one at a time in
 * equip order. afterFn is called when all prompts are handled or skipped.
 */
function setupDoomsdayBombPrompts(room, playerId, afterFn) {
  const player = room.players.get(playerId);
  if (!player || player.left || player.studentDead) { afterFn(); return; }

  // Collect indices of Doomsday Bombs with 1+ counters
  const bombIndices = [];
  for (let i = 0; i < (player.equips || []).length; i++) {
    const e = player.equips[i];
    if (e.name === 'Doomsday Bomb' && (e.doomCounters || 0) >= 1) {
      bombIndices.push(i);
    }
  }

  if (bombIndices.length === 0) { afterFn(); return; }

  // Process each bomb's prompt sequentially
  let queueIdx = 0;
  const processNext = () => {
    // Re-check since a previous detonation may have shifted indices
    // Re-scan for remaining Doomsday Bombs with counters
    const remaining = [];
    for (let i = 0; i < (player.equips || []).length; i++) {
      const e = player.equips[i];
      if (e.name === 'Doomsday Bomb' && (e.doomCounters || 0) >= 1) {
        remaining.push(i);
      }
    }
    if (queueIdx >= remaining.length) { afterFn(); return; }

    const equipIdx = remaining[queueIdx];
    const bomb = player.equips[equipIdx];
    if (!bomb) { queueIdx++; processNext(); return; }

    room.pendingDoomsdayBomb = {
      playerId,
      equipIndex: equipIdx,
      doomCounters: bomb.doomCounters || 0,
      afterFn: () => { queueIdx++; processNext(); },
    };

    console.log(`💣 Doomsday Bomb: prompting ${player.name} to detonate (${bomb.doomCounters} counters)`);
    broadcastRoomState(room);
  };

  processNext();
}

/**
 * Detonate a specific Doomsday Bomb: deal 4× counters to ALL targets,
 * discard the bomb, then continue the post-attack chain.
 */
function detonateDoomsdayBomb(room, playerId, equipIndex) {
  const player = room.players.get(playerId);
  if (!player) return;
  const bomb = player.equips[equipIndex];
  if (!bomb || bomb.name !== 'Doomsday Bomb') return;

  const counters = bomb.doomCounters || 0;
  const damage = 4 * counters;

  console.log(`💥💣 DOOMSDAY BOMB DETONATES! ${counters} counters → ${damage} damage to ALL targets!`);

  // Collect ALL targets EXCEPT the (formerly) equipped student
  const targets = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && !p.studentDead) {
      if (pid !== playerId) { // exclude the detonating player's own student
        targets.push({ playerId: pid, type: 'student' });
      }
    }
    for (let i = 0; i < (p.familiars || []).length; i++) {
      if (p.familiars[i] && p.familiars[i].currentHp > 0) {
        targets.push({ playerId: pid, type: 'familiar', familiarIndex: i });
      }
    }
  }

  // Remove the bomb BEFORE dealing damage (so the blast doesn't re-add counters to itself)
  player.equips.splice(equipIndex, 1);
  clampMagnetStacks(player);
  clampArmorStacks(player);
  clampInvisibleStacks(player);
  player.discardPile.push(bomb);
  trackBoardRemoval(room, playerId, 1);
  console.log(`💣 Doomsday Bomb discarded from ${player.name}'s board`);

  // Broadcast the screen-filling explosion animation
  room.doomsdayExplosionEvent = { casterId: playerId, damage };

  // Deal damage to all targets (Reverse Prism may reduce target list)
  const _doomAfter = () => {
    resolveTargetDamage(room, targets, damage, playerId, { damageCategory: 'effect' });
  };
  if (targets.length >= 2 && tryReversePrismSnare(room, targets, _doomAfter)) return;
  _doomAfter();
}

// ══════════════════════════════════════════════════════════════════════════
// FIELD STANDARD — simultaneous "untap a familiar" prompt after student damage
// ══════════════════════════════════════════════════════════════════════════

/**
 * Start the Field Standard simultaneous prompt phase.
 * All players in room.fieldStandardPending get prompted at the same time.
 * afterFn is called once every player has confirmed or cancelled.
 */
function enterFieldStandardPhase(room, afterFn) {
  const pending = room.fieldStandardPending;
  if (!pending || pending.size === 0) { afterFn(); return; }

  // Build per-player data: which tapped familiars they can untap, how many
  const eligible = new Map(); // playerId → { maxSelect, tappedList }
  for (const pid of pending) {
    const p = room.players.get(pid);
    if (!p || p.left || p.studentDead) continue;
    const tapped = (p.tappedFamiliars || []);
    if (tapped.length === 0) continue; // no tapped familiars — skip silently
    const maxSelect = Math.min(countFieldStandards(p), tapped.length);
    if (maxSelect === 0) continue;
    const tappedList = tapped.map(fi => ({
      familiarIndex: fi,
      name: (p.familiars[fi] && p.familiars[fi].name) || '???',
    }));
    eligible.set(pid, { maxSelect, tappedList });
  }

  room.fieldStandardPending = new Set(); // clear queue

  if (eligible.size === 0) { afterFn(); return; }

  const awaiting = new Set(eligible.keys());

  room.pendingFieldStandard = {
    eligible: Object.fromEntries(
      [...eligible.entries()].map(([pid, v]) => [pid, v])
    ),
    awaiting: [...awaiting],
    afterFn,
  };

  console.log(`🚩 Field Standard: ${eligible.size} player(s) may untap familiars`);
  broadcastRoomState(room);

  // Auto-cancel for disconnected players
  for (const pid of awaiting) {
    const p = room.players.get(pid);
    if (p && p.disconnected) {
      resolveFieldStandardForPlayer(room, pid, []);
    }
  }
}

/**
 * Apply a player's Field Standard selection (indices to untap), then check
 * if all players have responded.
 */
function resolveFieldStandardForPlayer(room, playerId, familiarIndices) {
  const pfs = room.pendingFieldStandard;
  if (!pfs || !pfs.awaiting.includes(playerId)) return;
  const player = room.players.get(playerId);

  if (player && familiarIndices.length > 0) {
    for (const fi of familiarIndices) {
      player.tappedFamiliars = (player.tappedFamiliars || []).filter(ti => ti !== fi);
      if (player.familiars[fi]) delete player.familiars[fi].sealedInIce;
      console.log(`🚩 Field Standard: ${player.name} untapped ${player.familiars[fi]?.name || 'familiar ' + fi}`);
    }
  }

  pfs.awaiting = pfs.awaiting.filter(id => id !== playerId);

  if (pfs.awaiting.length === 0) {
    const afterFn = pfs.afterFn;
    room.pendingFieldStandard = null;
    console.log(`🚩 Field Standard phase complete`);
    afterFn();
  } else {
    broadcastRoomState(room);
  }
}

function applyBombArrowShot(room, playerId, target, afterFn) {
  const player = room.players.get(playerId);
  const targetOwner = room.players.get(target.playerId);
  const targetName = target.type === 'student'
    ? (targetOwner?.chosenStudent?.name ?? 'student')
    : (targetOwner?.familiars?.[target.familiarIndex]?.name ?? 'familiar');
  resolveTargetDamage(room, [target], 5, playerId, { damageCategory: 'effect', noSnares: true });
  // Queue explosion animation (one-shot, cleared after broadcast)
  room.bombArrowExplosionEvent = { playerId: target.playerId, type: target.type, familiarIndex: target.familiarIndex ?? null };
  console.log(`🏹💣 Bomb Arrow: ${player?.name} dealt 5 damage to ${targetOwner?.name}'s ${targetName}`);
  afterFn();
}

/**
 * Returns true if Barrel Home is in play AND the given player already
 * controls 3 or more living Familiars (blocking further summoning).
 */
function isBarrelHomeBlocked(room, player) {
  if (!hasBarrelHome(room)) return false;
  const living = (player.familiars || []).filter(f => f && f.currentHp > 0).length;
  return living >= 3;
}

/**
 * Check if a familiar can be targeted by Barbarian Sword negation.
 * Resolves Clone originalName for the PASSIVE_FAMILIARS lookup.
 */
function isFamiliarNegatable(familiar) {
  if (!familiar) return false;
  const lookupName = familiar.isClone ? (familiar.originalName || familiar.name) : familiar.name;
  return PASSIVE_FAMILIARS.has(lookupName);
}

/**
 * Clear any lingering board state that is maintained by a familiar's passive.
 * Called immediately after setting passiveNegated = true on the familiar.
 * - Harpy Warrior: its harpyGuardTarget reference must be removed so the
 *   guarded target is no longer protected.
 */
function clearLingeringPassiveState(familiar) {
  if (!familiar) return;
  // Harpy Warrior: drop its guard assignment
  if (familiar.harpyGuardTarget) {
    delete familiar.harpyGuardTarget;
    console.log(`🗡️🚫 Harpy Warrior guard cleared — passive negated`);
  }
}

/**
 * Build eligible target list for Barbarian Sword negate prompt.
 * Eligible: alive, has passive (PASSIVE_FAMILIARS), not already passiveNegated,
 * not protected by Class Pet immunity or Futuristic Mech immunity.
 */
function getBarbarianSwordEligibleTargets(room) {
  const eligible = [];
  for (const [pid, p] of room.players) {
    if (p.left) continue;
    const classPetImmune = hasClassPetImmunity(p);
    for (let i = 0; i < (p.familiars || []).length; i++) {
      const f = p.familiars[i];
      if (!f || f.currentHp <= 0) continue;
      if (f.passiveNegated) continue;
      if (!isFamiliarNegatable(f)) continue;
      if (classPetImmune) continue;
      if (isMechImmune(f)) continue;
      eligible.push({ playerId: pid, familiarIndex: i, name: f.name });
    }
  }
  return eligible;
}

const SONG_OF_RAIN_TIMEOUT_MS = 10000;

function isRainy(room) {
  for (const [, p] of room.players) {
    if (p.left) continue;
    if ((p.equips || []).some(e => e.name === 'Song of Rain')) return true;
  }
  return false;
}

function hasShrink(player) {
  return (player.equips || []).some(e => !e.malfunctioning && e.name === 'Shrink');
}

function hasSpellShackles(player) {
  return (player.equips || []).some(e => !e.malfunctioning && e.name === 'Spell Shackles');
}

function getEffectiveStudentAtk(player) {
  // Mummy Guards Curse: student ATK is locked to 1, immune to all increases
  if (player.studentCursed) return 1;
  const base = player.chosenStudent ? (player.chosenStudent.currentAtk || 0) : 0;
  const bladeBonus = countAntiMagicBlades(player) * 4;
  const warhorseBonus = getWarhorseAtkBonus(player);
  const barbarianBonus = countBarbarianSwords(player) * 4;
  const bazookaBonus = countBazookas(player) * 10;
  const edgyCloakBonus = countEdgyCloaks(player) * 6;
  const halberdBonus = countHalberds(player) * 4;
  const phantomsSwordBonus = countPhantomsSwords(player) * (player.discardPile || []).length;
  const possessedBladeBonus = (player.equips || []).filter(e => !e.malfunctioning && e.name === 'Possessed Blade').length * 8;
  const scimitarBonus = countScimitars(player) * 4 + (player.scimitarPermAtk || 0);
  const bonusWithoutFists = bladeBonus + warhorseBonus + barbarianBonus + bazookaBonus + edgyCloakBonus + halberdBonus + phantomsSwordBonus + possessedBladeBonus + scimitarBonus;
  // Mechanized Fists: +10 ATK, but only if no other ATK-increasing effect is active
  // (i.e. effective ATK without Fists would be <= base). Multiple Fists = same as one.
  const fistsBonus = hasMechanizedFists(player) && (base + bonusWithoutFists) <= base ? 10 : 0;
  const total = base + bonusWithoutFists + fistsBonus;
  // Shrink: ATK is capped at 1 after all other bonuses
  if (hasShrink(player)) return Math.min(1, total);
  return total;
}

