/**
 * Get list of taunting targets for a player.
 * Returns array of { type: 'student'|'familiar', familiarIndex?, stacks }.
 */
function getPlayerTauntingTargets(player) {
  const result = [];
  if (player.chosenStudent && !player.studentDead && (player.chosenStudent.taunting || 0) > 0) {
    result.push({ type: 'student', stacks: player.chosenStudent.taunting });
  }
  for (let i = 0; i < (player.familiars || []).length; i++) {
    const f = player.familiars[i];
    if (f.currentHp > 0 && (f.taunting || 0) > 0) {
      result.push({ type: 'familiar', familiarIndex: i, stacks: f.taunting });
    }
  }
  return result;
}

/**
 * Check if a specific target is taunting.
 */
function isTargetTaunting(room, playerId, type, familiarIndex) {
  const p = room.players.get(playerId);
  if (!p) return false;
  if (type === 'student') return (p.chosenStudent?.taunting || 0) > 0;
  if (type === 'familiar') {
    const f = p.familiars?.[familiarIndex];
    return f ? (f.taunting || 0) > 0 : false;
  }
  return false;
}

/**
 * Validate taunting restriction for a set of targets.
 * Returns null if valid, or an error string if a violation is found.
 * @param {object} room
 * @param {string} attackerPlayerId - the player performing the action
 * @param {Array} targets - array of { playerId, type, familiarIndex? }
 * @param {object} [options] - { familiarsOnly, tappedOnly, untappedOnly, sourceType, sourceFamiliarIndex }
 */
function validateTauntingRestriction(room, attackerPlayerId, targets, options = {}) {
  for (const t of targets) {
    if (t.playerId === attackerPlayerId) continue; // self-targeting: no restriction
    const owner = room.players.get(t.playerId);
    if (!owner) continue;
    const tauntTargets = getPlayerTauntingTargets(owner);
    if (tauntTargets.length === 0) continue; // no taunting on this player

    // Check if the selected target is taunting — if so, always valid
    if (isTargetTaunting(room, t.playerId, t.type, t.familiarIndex)) continue;

    // Selected a non-taunting target — check if any taunting target is viable
    for (const tt of tauntTargets) {
      let viable = true;
      // familiarsOnly: student taunting doesn't block familiar targeting
      if (options.familiarsOnly && tt.type === 'student') viable = false;
      // tappedOnly: check if taunting target is tapped
      if (options.tappedOnly && viable) {
        if (tt.type === 'student' && !owner.tappedStudent) viable = false;
        if (tt.type === 'familiar' && !(owner.tappedFamiliars || []).includes(tt.familiarIndex)) viable = false;
      }
      // untappedOnly (exhaust/charm): check if taunting target is untapped
      if (options.untappedOnly && viable) {
        if (tt.type === 'student' && owner.tappedStudent) viable = false;
        if (tt.type === 'familiar' && (owner.tappedFamiliars || []).includes(tt.familiarIndex)) viable = false;
      }
      // Shy Girl: student hidden from familiar targeting
      if (tt.type === 'student' && options.sourceType === 'familiar') {
        if (isShyGirlProtected(room, t.playerId)) viable = false;
      }
      // Can't redirect to self (source familiar)
      if (tt.type === 'familiar' && t.playerId === attackerPlayerId
          && tt.familiarIndex === options.sourceFamiliarIndex) viable = false;
      if (viable) {
        return 'Must target a taunting target';
      }
    }
    // No viable taunting targets for this effect — non-taunting is allowed
  }
  return null;
}

/**
 * After an opponent's effect resolves, consume 1 taunting stack from each
 * taunting target that was hit. Only applies to opponent hits.
 */
function consumeTauntingStacks(room, attackerPlayerId, targets) {
  for (const t of targets) {
    if (t.playerId === attackerPlayerId) continue; // self-hit: no consumption
    const owner = room.players.get(t.playerId);
    if (!owner) continue;
    if (t.type === 'student' && owner.chosenStudent && (owner.chosenStudent.taunting || 0) > 0) {
      owner.chosenStudent.taunting--;
      console.log(`🛡️ Taunting consumed on ${owner.name}'s student (${owner.chosenStudent.taunting} remaining)`);
    } else if (t.type === 'familiar') {
      const f = owner.familiars?.[t.familiarIndex];
      if (f && (f.taunting || 0) > 0) {
        f.taunting--;
        console.log(`🛡️ Taunting consumed on ${owner.name}'s ${f.name} (${f.taunting} remaining)`);
      }
    }
  }
}

/**
 * Clear all taunting stacks from all targets in the room.
 * Called at end of round before proctor approvals.
 */
function clearAllTauntingStacks(room) {
  let cleared = 0;
  for (const [, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && (p.chosenStudent.taunting || 0) > 0) {
      p.chosenStudent.taunting = 0;
      cleared++;
    }
    for (const f of (p.familiars || [])) {
      if (!f) continue;
      if ((f.taunting || 0) > 0) {
        f.taunting = 0;
        cleared++;
      }
    }
  }
  if (cleared > 0) console.log(`🛡️ Cleared taunting from ${cleared} target(s) at end of round`);
}

/**
 * Clear all Rain's Blessing buffs at end of round (same timing as taunting).
 */
function clearAllRainsBlessing(room) {
  let cleared = 0;
  for (const [, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && p.chosenStudent.rainsBlessing) {
      p.chosenStudent.rainsBlessing = false;
      cleared++;
    }
    for (const f of (p.familiars || [])) {
      if (!f) continue;
      if (f.rainsBlessing) {
        f.rainsBlessing = false;
        cleared++;
      }
    }
  }
  if (cleared > 0) console.log(`🌧️ Cleared Rain's Blessing from ${cleared} target(s) at end of round`);
}

/**
 * Clear all Spiced-up buffs (Spice Mortar item) at end of round.
 */
function clearAllSpicedUp(room) {
  let cleared = 0;
  for (const [, p] of room.players) {
    if (p.left) continue;
    if (p.chosenStudent && p.chosenStudent.spicedUp) {
      p.chosenStudent.spicedUp = false;
      cleared++;
    }
  }
  if (cleared > 0) console.log(`🌶️ Cleared Spiced-up from ${cleared} student(s) at end of round`);
}

// ═══════════════════════════════════════════════════════════════════════════
//  TREACHEROUS CRYSTAL — discard-triggered familiar theft
// ═══════════════════════════════════════════════════════════════════════════

/**
 * At end of round, return all borrowed familiars to their original owners,
 * unless they died, left the board, or are under a *permanent* control effect.
 * A familiar is considered permanently stolen if its ownerPlayerId was changed
 * by a non-TC effect (we track TC loans with _tcLoanedFrom on the familiar).
 */
function returnTreacherousCrystalLoans(room) {
  for (const [pid, player] of room.players) {
    if (player.left) continue;
    const fams = player.familiars || [];
    for (let i = fams.length - 1; i >= 0; i--) {
      const fam = fams[i];
      if (!fam._tcLoanedFrom) continue;
      if ((fam.currentHp || 0) <= 0) {
        // Familiar is dead — just clear the loan marker
        delete fam._tcLoanedFrom;
        console.log(`💎 TC return: ${fam.name} died — loan marker cleared`);
        continue;
      }
      const originalOwnerId = fam._tcLoanedFrom;
      const originalOwner = room.players.get(originalOwnerId);
      if (!originalOwner || originalOwner.left || originalOwner.won) {
        // Original owner left/won — clear marker and keep familiar where it is
        delete fam._tcLoanedFrom;
        console.log(`💎 TC return: ${fam.name}'s original owner gone — keeping with ${player.name}`);
        continue;
      }
      // Return it
      const returned = fams.splice(i, 1)[0];
      delete returned._tcLoanedFrom;
      // Preserve tapped state — do NOT untap on return
      insertFamiliarSlot(originalOwner, returned);
      console.log(`💎 TC loan returned: ${returned.name} → back to ${originalOwner.name} (tapped: ${returned.tapped || false})`);
      if (!room.tcReturnEvents) room.tcReturnEvents = [];
      room.tcReturnEvents.push({ toPlayerId: originalOwnerId, familiarName: returned.name });
    }
  }
}

/**
 * Process next pending Treacherous Crystal familiar-pick.
 */
function processTreacherousCrystalQueue(room, afterFn) {
  if (!room._treacherousCrystalQueue || room._treacherousCrystalQueue.length === 0) {
    room.pendingTreacherousCrystal = null;
    afterFn();
    return;
  }

  const entry = room._treacherousCrystalQueue.shift();
  const player = room.players.get(entry.playerId);

  if (!player || player.left) {
    processTreacherousCrystalQueue(room, afterFn);
    return;
  }

  // Gather all living opponent familiars
  const targets = [];
  for (const [pid, p] of room.players) {
    if (pid === entry.playerId || p.left || p.won) continue;
    (p.familiars || []).forEach((fam, idx) => {
      if ((fam.currentHp || 0) > 0) {
        targets.push({ ownerId: pid, ownerName: p.name, familiarIndex: idx, familiarName: fam.name, path: fam.path });
      }
    });
  }

  if (targets.length === 0) {
    console.log(`💎 Treacherous Crystal: ${entry.playerName} — no opponent familiars remain, skipping`);
    processTreacherousCrystalQueue(room, afterFn);
    return;
  }

  const tcCard = allNormalCards.find(c => c.name === 'Treacherous Crystal')
    || { name: 'Treacherous Crystal', path: '/cards/Treacherous Crystal.png', type: 'Item' };
  room.activeSpell = { ...tcCard, passiveEffect: true };
  room.activeSpellPlayer = entry.playerName;

  room.pendingActivation = {
    playerId: entry.playerId,
    sourceType: 'item',
    familiarIndex: -1,
    effectType: 'tc-steal-familiar',
    canCancel: false,
    // afterFn stored on room._tcAfterFn (not on PA — functions don't survive JSON/reconnect)
  };
  room._tcAfterFn = afterFn;

  console.log(`💎 Treacherous Crystal: prompting ${entry.playerName} to steal a familiar (${targets.length} targets)`);
  broadcastRoomState(room);
}

