        startWeakeningCrystalChain(room, 5, ffsDamageTargets, (wcDmgFFS) => {
        resolveTargetDamage(room, ffsDamageTargets, wcDmgFFS, socket.id, {});
        console.log(`🔥🗿 ${player.name} plays Flame Fairy Statue — Energized ${ffsDamageTargets.length} tapped target(s) for ${wcDmgFFS} damage each`);
        // Fire Arson Trap trigger on the energized targets
        const _ffsArsonTrigger = {
          type: 'target-energized',
          sourcePlayerId: socket.id,
          energizedTargets: ffsDamageTargets.map(t => ({ playerId: t.playerId, type: t.type, familiarIndex: t.familiarIndex ?? -1 })),
        };
        const _ffsAfterArson = () => {
          // Drain trigger queues (deaths, taps, etc.) without advancing turn
          room._itemEffectActive = true;
          const transitioning = advanceExamTurn(room);
          if (!transitioning) {
            delete room._itemEffectActive;
            broadcastRoomState(room);
          }
        };
        if (startSnareReaction(room, _ffsArsonTrigger, _ffsAfterArson)) return;
        _ffsAfterArson();
        }); // end startWeakeningCrystalChain Flame Fairy Statue
        return;
