    const recovered = [];
    for (const { owner, idx } of sources) {
      const card = owner.discardPile.splice(idx, 1)[0];
      delete card.looming; delete card.loomingOwner;
      card.revealed = true;
      recovered.push(card);
    }
    for (const card of recovered.reverse()) {
      player.hand.push(card);
    }
    trackHandAddition(room, socket.id, recovered.length, true);
    console.log(`🌠 ${player.name} wishes for "${cardName}" — recovered ${recovered.length} cop${recovered.length === 1 ? 'y' : 'ies'}`);

