    if (!room || room.phase !== 'exam') return;
    if (!room.pendingActivation || room.pendingActivation.effectType !== 'awaiting-give') return;
    if (room.pendingActivation.givePlayerId !== socket.id) return;

    const giver = room.players.get(socket.id);
