    delete stolen.looming; delete stolen.loomingOwner;
    const knownToAll = stolen.revealed || stolen.chillyWizzyRevealed || stolen.prophecyStamped || stolen.blueprintRevealed;
    if (!knownToAll) {
      // Card was private — preserve existing revealedTo viewers and add the giver
      if (!stolen.revealedTo) stolen.revealedTo = [];
      if (!stolen.revealedTo.includes(socket.id)) stolen.revealedTo.push(socket.id);
    }
    // If already public, keep all reveal flags as-is so it stays known to everyone
    recipient.hand.push(stolen);
    trackHandAddition(room, room.pendingActivation.recipientPlayerId, 1);

    console.log(`🐀 ${giver.name} gives "${stolen.name}" to ${recipient.name}`);

